firmware_template.source:
#include "nixie_display.h"
#include <SPI.h>
#define LATCH 5
void nixie_setup(){SPI.begin();pinMode(LATCH,OUTPUT);Serial.println("[nixie] OK");}
void nixie_show_number(uint32_t n,uint8_t d){digitalWrite(LATCH,LOW);for(int i=d-1;i>=0;i--){SPI.transfer((n/(uint32_t)pow(10,i))%10);}digitalWrite(LATCH,HIGH);}
void nixie_show_time(uint8_t h,uint8_t m,uint8_t s){nixie_show_number(h*10000+m*100+s,6);}
void nixie_blank(){digitalWrite(LATCH,LOW);for(int i=0;i<8;i++)SPI.transfer(0xFF);digitalWrite(LATCH,HIGH);}
